INSERT INTO public.photos VALUES (23610, 'Coso Medio c.1900', 'Archivo Municipal. Hauser y Menet (Madrid). 1897-1900. "Zaragoza. El Coso." Fotografâ”œÂ¡a utilizada por la casa Editorial "Hauser y Menet" para postal impresa. En la imagen, el Coso Medio capturado desde la plaza de la Constituciâ”œâ”‚n. A la izquierda, el Teatro Principal. Circulan tranvâ”œÂ¡as a propulsiâ”œâ”‚n de sangre. La postal fue escrita y fechada en Almazâ”œÃ­n (Soria), el 24-11-1903, con el texto "De no recibir telegrama despuâ”œÂ®s de esta postal, es seguro que maâ”œâ–’ana 25 a las 10 de la noche tendrâ”œÃ­ el placer de abrazarte tu padre." Lleva sello postal de 10 câ”œÂ®ntimos (de Alfonso XIII niâ”œâ–’o) matasellado.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.65177700, -0.87967800, '0101000020E61000008E57207A5226ECBF7BA4C16D6DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15436958430.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15436958430.webp', 'https://www.flickr.com/photos/zaragozaantigua/15436958430/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23611, 'Calle Porcell 1957', 'Vista de la calle Porcell en direcciâ”œâ”‚n Sur, donde se encuentra con San Miguel, al fondo. A la izquierda, el nâ”¬â•‘ 7 de la calle, perteneciente al Colegio de Santa Ana, que se extendâ”œÂ¡a hasta el Coso. Luego, el nâ”¬â•‘ 17 de San Miguel, de 1923. Enfrente, el nâ”¬â•‘ 16 de San Miguel, de los aâ”œâ–’os 30 del s.XX. A la derecha, la fachada lateral de la central elâ”œÂ®ctrica que llegaba hasta la calle Jerâ”œâ”‚nimo Blancas. Por tener sâ”œâ”‚lo una altura, y ese tejado a doble vertiente, el sol penetra en la calle Porcell e ilumina a dos niâ”œâ–’as paseantes, como ya nunca mâ”œÃ­s lo harâ”œÃ­ cuando la central sea piqueteada y sustituida por el actual bloque de seis alturas, poco tiempo despuâ”œÂ®s. Cierra el recorrido el edificio-almacâ”œÂ®n de la derecha. La calle parece mâ”œÃ­s ancha, con sus aceras de juguete, sus recios bordillos, y ese adoquinado tan incâ”œâ”‚modo para zapatos de alto tacâ”œâ”‚n. Fuente: "Zaragoza viva" (1969)', 1957, 1957, 1957, 'Anos 50', 'CENTRO', 41.65095700, -0.87941000, '0101000020E6100000C0CFB8702024ECBF170D198F52D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15671790810.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15671790810.webp', 'https://www.flickr.com/photos/zaragozaantigua/15671790810/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23612, 'Coso Medio 1937', 'Desfile de la Tercera Bandera de Falange, proveniente del frente de la Sierra de Alcubierre, que llegaba a descansar a los acuartelamientos de la ciudad. Al fondo, cartel de la Imprenta de Heraldo de Aragâ”œâ”‚n, en el nâ”¬â•‘ 100 del Coso (aunque la sede central ya estaba en Independencia nâ”¬â•‘ 29), en la manzana entre las calles de Santa Catalina (justo a su izquierda) y de Porcell. Fuente: www.facebook.com/photo.php?fbid=869755063057693&set=o...', 1937, 1937, 1937, 'Anos 30', 'CENTRO', 41.65173400, -0.87958300, '0101000020E61000001EC3633F8B25ECBF7BD80B056CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15704855718.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15704855718.webp', 'https://www.flickr.com/photos/zaragozaantigua/15704855718/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23614, 'Pedro Joaquâ”œÂ¡n Soler 1951', 'Imagen de la calle Pedro Joaquâ”œÂ¡n Soler capturada desde el Coso Medio, cuando eran muy otros los edificios que la flaqueaban, asâ”œÂ¡ como su anchura. Al fondo, los edificios de la calle de la Verâ”œâ”‚nica. A la derecha quedaba la plazuela de la Verâ”œâ”‚nica. Sobre todos estos elementos, iluminada, una torre de la Iglesia del Sagrado Corazâ”œâ”‚n de la plaza de San Pedro Nolasco. Fuente visual: Archivo Municipal. Archivo Mora. Junio 1951.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.65115500, -0.87773400, '0101000020E6100000DECA129D6516ECBF3ED00A0C59D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18048230774.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18048230774.webp', 'https://www.flickr.com/photos/zaragozaantigua/18048230774/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23618, 'Teatro Principal 1962', 'Foto: Gerardo Sancho Ramo. Fachada del Teatro Principal de Zaragoza en el nâ”œâ•‘mero 57 del Coso Medio, ornada con motivo alusivo a la celebraciâ”œâ”‚n de las fiestas patronales, en este caso como sede de la Semana Nacional de la Jota. Fuente: AMZ.', 1962, 1962, 1962, 'Anos 60', 'CENTRO', 41.65179100, -0.87929200, '0101000020E6100000444DF4F92823ECBFE06932E36DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22218601886.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22218601886.webp', 'https://www.flickr.com/photos/zaragozaantigua/22218601886/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23624, 'Coso Medio 1902', 'Imagen capturada desde la altura de la antigua calle de los Sitios, con una vista del soleado tramo medio del Coso en sus nâ”œâ•‘meros impares, desde el Teatro Principal y el Banco de Espaâ”œâ–’a hasta la calle de Espartero. Sobresalen, emergiendo sobre el fondo, la torre de la iglesia parroquial de la Marâ”œÂ¡a Magdalena, y la torre del Seminario Sacerdotal de San Carlos. Fuente visual: Guâ”œÂ¡a de Zaragoza 1902.', 1902, 1902, 1902, 'Anos 1900', 'CENTRO', 41.65171600, -0.87947700, '0101000020E6100000B3B112F3AC24ECBFD5230D6E6BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35136734572.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35136734572.webp', 'https://www.flickr.com/photos/zaragozaantigua/35136734572/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23626, 'Coso Medio 1949', 'Imagen capturada en el arranque del tramo medio del Coso a la altura del Teatro Principal, donde figura en cartel la exitosa revista "Melodâ”œÂ¡as del Danubio" de la compaâ”œâ–’â”œÂ¡a Los Vieneses de Artur Kaps, donde destacaba el câ”œâ”‚mico Franz Joham. De procedencia austrâ”œÂ¡aca, las giras de esta compaâ”œâ–’â”œÂ¡a estaban determinadas desde 1940 por el progresivo alejamiento fâ”œÂ¡sico de la Europa dominada directamente por el Râ”œÂ®gimen nazi (Kaps y Joham eran judâ”œÂ¡os), de forma que en 1942 acabaron recalando en Espaâ”œâ–’a, en Barcelona, donde iniciaron una longeva carrera artâ”œÂ¡stica especialmente exitosa en las dos dâ”œÂ®cadas posteriores, impulsada de forma popular en el nuevo medio televisivo. Centra la escena el coche 158, un Topolino en servicio en la lâ”œÂ¡nea 1. Bajo Aragâ”œâ”‚n del tranvâ”œÂ¡a, reciâ”œÂ®n circulando en direcciâ”œâ”‚n a Miguel Servet, antes de que se habilitara el bucle que rodearâ”œÂ¡a el Teatro Principal y trasladarâ”œÂ¡a el inicio de lâ”œÂ¡nea a su parte trasera, en la calle de Valentâ”œÂ¡n Zabala. Al fondo y a la izquierda, "el Palomar" del Casino Mercantil. Fuente visual: Colecciâ”œâ”‚n particular.', 1949, 1949, 1949, 'Anos 40', 'CENTRO', 41.65171600, -0.87947700, '0101000020E6100000B3B112F3AC24ECBFD5230D6E6BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47052703411.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47052703411.webp', 'https://www.flickr.com/photos/zaragozaantigua/47052703411/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23627, 'Coso Medio c.1895', 'Inâ”œÂ®dita imagen capturada en altura desde la umbrâ”œÂ¡a del inmueble del nâ”¬â•‘ 72 del Coso Medio, esquinero con la calle de los Sitios, con una buena panorâ”œÃ­mica del soleado tramo de los nâ”œâ•‘meros impares, desde el 61, a la izquierda, inmediato al Teatro Principal, cuya fachada presenta el aspecto dado por la reforma diseâ”œâ–’ada en 1870 por Ricardo Magdalena, y hasta el fondo a la derecha, donde se destaca luminoso el antiguo nâ”¬â•‘ 1 en el arranque de la calle de Baldomero Espartero. Sobre el firme, tendido tranviario de las lâ”œÂ¡neas del Bajo Aragâ”œâ”‚n y de Circunvalaciâ”œâ”‚n, con servicio de coches traccionados por caballerâ”œÂ¡as.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.65171900, -0.87948500, '0101000020E610000069520ABABD24ECBF469737876BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48060025631.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48060025631.webp', 'https://www.flickr.com/photos/zaragozaantigua/48060025631/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23630, 'Coso Medio c.1900', 'Imagen de detalle centrada en el inmueble del nâ”¬â•‘ 61 del tramo medio del Coso, propiedad de Luis Isâ”œÃ­bal, secretario de la Câ”œÃ­mara de Comercio de Zaragoza, donde estaba radicada la redacciâ”œâ”‚n, imprenta y administraciâ”œâ”‚n de "El Diario de Zaragoza. Periâ”œâ”‚dico independiente", pionero del periodismo en Zaragoza desde 1797, ademâ”œÃ­s de sucursal de "La Moda Elegante" y "La Ilustraciâ”œâ”‚n Espaâ”œâ–’ola". En 1908 este periâ”œâ”‚dico fue redenominado "Diario de Avisos de Zaragoza", desapareciendo de esta forma la histâ”œâ”‚rica cabecera. El edificio tambiâ”œÂ®n acogâ”œÂ¡a, en la planta superior, el Colegio de San Josâ”œÂ® con su aulario para "Seâ”œâ–’oritos" y para "Seâ”œâ–’oritas". A la derecha y fuera de plano, el Teatro Principal de Zaragoza. Este caserâ”œâ”‚n, reliquia habitacional de la antigua Zaragoza, posiblemente de los siglos XVI-XVII, fue derribado durante los prodigiosos aâ”œâ–’os sesenta y sustituido por un horror de nueve alturas, construido para darle un toque mâ”œÃ­s moderno a este tramo del Coso.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.65189500, -0.87959200, '0101000020E6100000EB573A1F9E25ECBF85B69C4B71D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50096544887.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50096544887.webp', 'https://www.flickr.com/photos/zaragozaantigua/50096544887/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23632, 'Coso Medio 1962', 'Imagen capturada en el Coso Medio, con el telâ”œâ”‚n de fondo edilicio entre las calles de Eusebio Blasco y San Vicente de Paâ”œâ•‘l, durante el transcurso del "Gran Pregâ”œâ”‚n de Fiestas" celebrado la maâ”œâ–’ana del 7 de octubre de 1962. Destaca en primer tâ”œÂ®rmino y a caballo el pregonero Ignacio Moreno y su paje a pie, disfrazados con hâ”œÃ­bitos neomedievales, seguidos de los maceros, timbaleros u trompetas municipales, una furgoneta con publicidad de "Mistol", y una de las carrozas que formaban parte de la nutrida comitiva (la titulada "Boa", con "seâ”œâ–’oritas" hispanoamericanas). Sobre el adoquinado firme, vâ”œÂ¡as del tranvâ”œÂ¡a incluyendo el ramal de la lâ”œÂ¡nea 13 "San Josâ”œÂ®" que curvea hacia la terminal de la calle de Valentâ”œÂ¡n Zabala.', 1962, 1962, 1962, 'Anos 60', 'CENTRO', 41.65162300, -0.87917400, '0101000020E6100000C9CA2F833122ECBF2429E96168D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51669267856.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51669267856.webp', 'https://www.flickr.com/photos/zaragozaantigua/51669267856/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23633, 'Teatro romano siglo I', 'Recreaciâ”œâ”‚n infogrâ”œÃ­fica del teatro romano de Caesaraugusta. Imagen utilizada en la promociâ”œâ”‚n de un documental de 2022 sobre las estructuras en la ingenierâ”œÂ¡a romana.', 50, NULL, 99, 'Siglo XIX', 'CENTRO', 41.65214700, -0.87779000, '0101000020E6100000D72FD80DDB16ECBF9E978A8D79D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52502955167.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52502955167.webp', 'https://www.flickr.com/photos/zaragozaantigua/52502955167/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23951, 'Teatro Romano 1972', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. Mayo 1972. El Teatro Romano de Caesaraugusta fue uno de los mayores de toda Hispania (capacidad para 6.000 espectadores en una urbe de unos 18.000 habitantes). Edificado en â”œÂ®poca de Tiberio (14-37) y finalizado en â”œÂ®poca de Claudio (41-54), siguiendo el modelo del Teatro Marcelo de Roma. Su estructura, formada por anillos concâ”œÂ®ntricos reforzados por muros radiales, estâ”œÃ­ construida en aglomerado de hormigâ”œâ”‚n de cal y canto y recubierta con placas de piedra caliza. Al no apoyar su graderâ”œÂ¡o en ninguna colina, se creâ”œâ”‚ un sistema de galerâ”œÂ¡as abovedadas que permite la circulaciâ”œâ”‚n interior. Es el â”œâ•‘nico teatro peninsular con una fosa bajo el escenario para acceso de los actores en ciertos momentos de la obra. Conserva buena parte de sus estructuras, como la cavea, la orchestra, el balteus, hyposcenium, la cripta y los espacios entre los muros radiales de la cavea. Su â”œÂ®poca de mayor esplendor corresponde a las dinastâ”œÂ¡as Julio-Claudia y Flavia (siglo I). En el siglo III es abandonado, expoliado y sus ruinas se reaprovechan como cimientos de viviendas posteriores, e incluso aparecen restos de una necrâ”œâ”‚polis visigâ”œâ”‚tica. Como teatro, permaneciâ”œâ”‚ oculto bajo el urbanismo de la ciudad. Fue redescubierto en 1972, cuando un vecino alertâ”œâ”‚ a la prensa de la existencia de restos arqueolâ”œâ”‚gicos en una obra en construcciâ”œâ”‚n. La imagen, durante la difusiâ”œâ”‚n del fenomenal hallazgo, tomada desde un edificio de la vecina calle San Jorge. Al fondo, tras la valla, la calle Verâ”œâ”‚nica.', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65248100, -0.87760200, '0101000020E610000024EF1CCA5015ECBF7521567F84D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14710649739.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14710649739.webp', 'https://www.flickr.com/photos/zaragozaantigua/14710649739/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23967, 'Calle de la Verâ”œâ”‚nica 1974', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. Diciembre 1974. La Caja de Ahorros de Zaragoza, Aragâ”œâ”‚n y Rioja tenâ”œÂ¡a intenciâ”œâ”‚n de construir en el "solar" entre San Jorge y la Verâ”œâ”‚nica su nueva sede central, pero la sâ”œâ•‘bita apariciâ”œâ”‚n de un teatro romano de apenas capacidad para 6.000 espectadores desaconsejâ”œâ”‚ mantener el proyecto constructivo. La entidad de ahorro se buscâ”œâ”‚ otro sitio, que pronto encontrâ”œâ”‚ en un no mal lugar. Mientras, el solar del hallazgo fue enmurado, y los muros customizados con publicidad corporativa, ademâ”œÃ­s de los entonces ya ilegales cristales rotos en el borde superior para evitar el acceso. En la imagen, vista desde la calle de la Verâ”œâ”‚nica del muro tras el que estâ”œÃ­ el teatro romano. A la izquierda, sobresale una de las torres de la iglesia de San Pedro Nolasco. A la derecha, la calle Pedro Joaquâ”œÂ¡n Soler.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.65188700, -0.87787600, '0101000020E61000007B2FBE688F17ECBF02D8800871D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15062502798.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15062502798.webp', 'https://www.flickr.com/photos/zaragozaantigua/15062502798/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23982, 'Teatro Romano 2002', 'Josâ”œÂ® Miguel Marco. Octubre 2002. Imagen desde globo aerostâ”œÃ­tico del entorno del antiguo Teatro Romano de la ciudad, con las obras comenzadas para convertir en realidad el proyecto museogrâ”œÃ­fico asociado que serâ”œÃ­ inaugurado al aâ”œâ–’o siguiente, incluyendo la cobertura del conjunto. Fotografâ”œÂ¡a realizada con la Plaza de San Pedro Nolasco al fondo, la calle Pedro Joaquâ”œÂ¡n Soler a la derecha, y los â”œÃ­rboles, en primer plano, de la calle de la Verâ”œâ”‚nica.', 2002, 2002, 2002, 'Siglo XXI', 'CENTRO', 41.65215200, -0.87767200, '0101000020E61000005CAD1397E315ECBFB0027CB779D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15354244452.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15354244452.webp', 'https://www.flickr.com/photos/zaragozaantigua/15354244452/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24014, 'Teatro romano 2001', 'Vista del teatro romano de Zaragoza, antes de su musealizaciâ”œâ”‚n, inaugurada en 2003. Al fondo, calle de San Jorge y el Pilar. Fuente: Agencia EFE.', 2001, 2001, 2001, 'Siglo XXI', 'CENTRO', 41.65215200, -0.87767200, '0101000020E61000005CAD1397E315ECBFB0027CB779D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24283729469.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24283729469.webp', 'https://www.flickr.com/photos/zaragozaantigua/24283729469/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21629, 'Cabezo de Buenavista 1929', 'Dibujo del ilustrador turolense Manuel Bayo Marâ”œÂ¡n donde se representa el monumento erigido en 1923 al rey Alfonso I en el Cabezo de Buenavista con la blanca escultura del Batallador tallada por Josâ”œÂ® Bueno, a la que en 1927 se aâ”œâ–’adiâ”œâ”‚ la figura de un metâ”œÃ­lico y oscuro leâ”œâ”‚n a sus pies. El suspirante monarca medieval aparece compungido y quejoso tras la reciente derrota pugilâ”œÂ¡stica de Paulino Uzcudun ("el Leâ”œâ–’ador vasco") ante el alemâ”œÃ­n Max Schmeling en el Yankee Stadium (Nueva York). Al fondo, una veraniega y simpâ”œÃ­tica luna llena ilumina el nocturno cielo sobre el Cabezo. Fuente visual: www.mecd.gob.es/.', 1929, 1929, 1929, 'Anos 20', 'UNIVERSIDAD', 41.63366800, -0.89337000, '0101000020E6100000D847A7AE7C96ECBFC84274081CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37809897881.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37809897881.webp', 'https://www.flickr.com/photos/zaragozaantigua/37809897881/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24027, 'Manuel Machado 1931', 'Apenas diez dâ”œÂ¡as despuâ”œÂ®s de la proclamaciâ”œâ”‚n de la Segunda Repâ”œâ•‘blica, tuvo lugar el estreno de la obra de teatro "La prima Fernanda" en el Teatro Reina Victoria de Madrid, una composiciâ”œâ”‚n escrita por los hermanos Machado (Antonio, y Manuel), sobre un tema de actualidad: la corrupciâ”œâ”‚n polâ”œÂ¡tica en el contexto de la etapa final de la Dictadura de Primo de Rivera. Fue un fracaso total, pues el experimento de juntar en verso, y en tono de "alta" comedia, la corrupciâ”œâ”‚n polâ”œÂ¡tica en las instituciones, y las andanzas de la alta burguesâ”œÂ¡a implicada (por eso lo de "alta" comedia"), debiâ”œâ”‚ parecer demasiado para el cultivado pâ”œâ•‘blico de la â”œÂ®poca. En la imagen, capturada en el escenario del Teatro Principal de Zaragoza a mediados de febrero de ese aâ”œâ–’o, aparece a la derecha el poeta Manuel Machado, que simula la lectura de esta obra a la compaâ”œâ–’â”œÂ¡a de Irene Lâ”œâ”‚pez Heredia, encargada de su escenificaciâ”œâ”‚n. Inmediata a â”œÂ®l, Irene Lâ”œâ”‚pez Heredia, con el protagâ”œâ”‚nico papel de "Fernanda". A su lado, el actor Mariano Urdiaâ”œÂ¡n Asquerino, que encarnarâ”œÃ­ a "Leopoldo", el burguâ”œÂ®s metido en oscuros entresijos polâ”œÂ¡ticos. Desde 1925 era padre de una niâ”œâ–’a de nombre "Dulce Nombre de Marâ”œÂ¡a", que aâ”œâ–’os despuâ”œÂ®s serâ”œÂ¡a conocida como Marâ”œÂ¡a Asquerino. El tremendo câ”œÃ­nido, resignado y sin papel, como ausente. Fuente visual: Foto Marâ”œÂ¡n Chivite, para ABC.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65179100, -0.87929200, '0101000020E6100000444DF4F92823ECBFE06932E36DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24797319632.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24797319632.webp', 'https://www.flickr.com/photos/zaragozaantigua/24797319632/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '20