INSERT INTO public.photos VALUES (24058, 'Coso Medio 1931', 'Foto: Miguel Marâ”œÂ¡n Chivite. Celebraciones por la llegada de la Segunda Repâ”œâ•‘blica, el 14 de abril de 1931. Al fondo, la plaza de la Constituciâ”œâ”‚n. Fuente: Heraldo de Aragâ”œâ”‚n.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65171600, -0.87947700, '0101000020E6100000B3B112F3AC24ECBFD5230D6E6BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31746954805.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31746954805.webp', 'https://www.flickr.com/photos/zaragozaantigua/31746954805/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24075, 'Calle Verâ”œâ”‚nica c.1985', 'Vista de los restos del Teatro romano de Zaragoza en el solar entre la calle de La Verâ”œâ”‚nica (izquierda) y la de San Jorge. Al fondo, calle de Don Jaime I.', 1985, 1985, 1985, 'Anos 80', 'CENTRO', 41.65202000, -0.87791900, '0101000020E61000004D2F3196E917ECBF412B306475D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36885817824.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36885817824.webp', 'https://www.flickr.com/photos/zaragozaantigua/36885817824/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24113, 'Calle de Don Jaime I 1908', 'Imagen capturada en la calle de Don Jaime I durante la visita del rey Alfonso XIII el dâ”œÂ¡a 14 de junio de ese aâ”œâ–’o a diversos eventos relacionados con el primer centenario del asedio francâ”œÂ®s de 1808. En este caso se trata del descubrimiento de la lâ”œÃ­pida conmemorativa del general Antonio Torres Gimeno por su actuaciâ”œâ”‚n el cuatro de agosto de 1808, ubicada en la fachada del inmueble del nâ”¬â•‘ 50 de la calle, en recuerdo del antiguo edificio en el que viviâ”œâ”‚ el citado general y que fue derribado y reedificado a finales del siglo XIX, siendo â”œÂ®ste propiedad de Antonio Hernâ”œÃ­ndez Fajarnâ”œÂ®s, en cuyos bajos destaca la prestigiosa y gran joyerâ”œÂ¡a de Josâ”œÂ® Tarongi. A la izquierda, vista parcial del Gran Hotel de las Cuatro Naciones y del Universo.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.65353100, -0.87820800, '0101000020E6100000F9BCE2A9471AECBF0AF65FE7A6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52054175603.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52054175603.webp', 'https://www.flickr.com/photos/zaragozaantigua/52054175603/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24231, 'Calle de San Andrâ”œÂ®s 1947', 'Vista de la calle de San Andrâ”œÂ®s, con la de San Jorge al fondo, al paso de la comparsa de Gigantes y Cabezudos. Fuente: www.facebook.com/photo.php?fbid=10208729312283778&set...', 1947, 1947, 1947, 'Anos 40', 'CENTRO', 41.65280800, -0.87823100, '0101000020E610000004ABEAE5771AECBF994869368FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28142940636.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28142940636.webp', 'https://www.flickr.com/photos/zaragozaantigua/28142940636/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24352, 'San Andrâ”œÂ®s aâ”œâ–’os 20', 'AYUNTAMIENTO ZARAGOZA/Archivo MORA. Finales dâ”œÂ®cada 1920. Iglesia de San Andrâ”œÂ®s (Apâ”œâ”‚stol), sita en la calle del mismo nombre. Emplazada dentro del muro que delimitaba el barrio judâ”œÂ¡o viejo de la ciudad, hay quien opina que fue concebida como sinagoga (menor) hasta que a comienzos del siglo XIII fue reconvertida a catâ”œâ”‚lica y apostâ”œâ”‚lica parroquia. Muy vinculada a la Cofradâ”œÂ¡a de Ganaderos, prâ”œÃ­cticamente se convirtiâ”œâ”‚ en su gremial parroquia. De factura modesta, fue construida en ladrillo, siguiendo los estâ”œÃ­ndares mudâ”œÂ®jares. Una â”œâ•‘nica nave cubierta con crucerâ”œÂ¡a sencilla, testa recta y tres capillas de fondo, y con 5 capillas a cada lado, entre los contrafuertes laterales. En el siglo XVII la Contrarreforma la barroquizâ”œâ”‚ en forma y estilo, como ilustra el tâ”œÂ¡mpano quebrado de la puerta de acceso. Cesâ”œâ”‚ sus actividades como parroquia en 1896, siendo derribada en 1930. Su patrimonio artâ”œÂ¡stico fue repartido entre varias iglesia de la ciudad, como la parroquia de S. Valero. En la imagen, vista de la Iglesia capturada desde el otro lado de la calle de San Andrâ”œÂ®s, sobre el tejadillo de las traseras del actual nâ”¬â•‘ 16 de D. Jaime. A su izquierda queda la Casa y Cofradâ”œÂ¡a de Ganaderos de Zaragoza. En la actualidad todo ese espacio estâ”œÃ­ ocupado por el enorme bloque de viviendas que chaflanea S. Andrâ”œÂ®s con Verâ”œâ”‚nica, y llega hasta el Teatro Romano. Un buen mordisco.', 1920, 1920, 1929, 'Anos 20', 'CENTRO', 41.65255300, -0.87848700, '0101000020E6100000C2C1DEC4901CECBF0EF450DB86D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14872754253.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14872754253.webp', 'https://www.flickr.com/photos/zaragozaantigua/14872754253/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24362, 'San Gil 1966', 'Ayuntamiento de Zaragoza/Gerardo Sancho, 24/12/66. Calle Estâ”œÂ®banes de Zaragoza, desde Don Jaime. Vista de la torre de la iglesia de San Gil.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65276600, -0.87918900, '0101000020E61000001E1840F85022ECBF6AF816D68DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15024671980.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15024671980.webp', 'https://www.flickr.com/photos/zaragozaantigua/15024671980/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22165, 'RS Josâ”œÂ® Antonio 1955', 'Imagen centrada en la capilla de la Residencia Sanitaria Josâ”œÂ® Antonio, diseâ”œâ–’ada por el arquitecto Fernando Garcâ”œÂ¡a Mercadal. Adosada a la izquierda del escalonado brazo edilicio que conectaba el original ambulatorio con el cuerpo principal del nuevo hospital, esta dependencia religiosa (modificada, por cierto, respecto a la que aparecâ”œÂ¡a en la maqueta del proyecto) representaba una leve concesiâ”œâ”‚n al clasicismo dentro del tono racionalista y funcional diseâ”œâ–’o global del conjunto, con su planta circular y llamativa câ”œâ•‘pula, visible a distancia. Su espacio interior se articulaba en dos plantas, una cripta en el piso inferior, y la capilla propiamente dicha en el piso superior, de mâ”œÃ­s altura y culminada por un espacio delimitado por una balaustrada soportada por un entablamiento sobre ocho columnas y cubierto por la câ”œâ•‘pula. El altar fue ubicado en el prisma adosado a la izquierda, con verticales ventanales y tejado a dos aguas. Esta capilla fue derribada en una de las ampliaciones del complejo hospitalario, posiblemente la acometida por el Instituto Nacional de la Salud a principios de los aâ”œâ–’os ochenta, cuando ademâ”œÃ­s esta "Ciudad Sanitaria Jose Antonio" fue finalmente redenominada "Hospital Miguel Servet". Fuente visual: bancodeimagenesmedicina.com', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.63537800, -0.90032100, '0101000020E610000051DD5CFC6DCFECBF884CF91054D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30866903308.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30866903308.webp', 'https://www.flickr.com/photos/zaragozaantigua/30866903308/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24375, 'Calle de San Andrâ”œÂ®s 1918', 'Imagen de la Iglesia de San Andrâ”œÂ®s (el Protocletos), en la calle del mismo nombre. Hay quien opina que originalmente fue sinagoga (menor) de la juderâ”œÂ¡a, hasta que a comienzos del s. XIII fue reconvertida a catâ”œâ”‚lica parroquia, aunque tambiâ”œÂ®n menor, pues hacâ”œÂ¡a de iglesia gremial de la inmediata Cofradâ”œÂ¡a de Ganaderos. Su fâ”œÃ­brica era modesta, mudâ”œÂ®jar, en ladrillo. Una â”œâ•‘nica nave cubierta con crucerâ”œÂ¡a sencilla, testa recta, tres capillas de fondo, y 5 capillas a cada lado. Su pequeâ”œâ–’a torre, en ladrillo, con leves paâ”œâ–’os horizontales como leve decoraciâ”œâ”‚n, y remate en techillo inclinado de teja. En el s. XVII la Contrarreforma la barroquizâ”œâ”‚, como indica el pequeâ”œâ–’o tâ”œÂ¡mpano quebrado de la puerta. Cesâ”œâ”‚ sus actividades confesionales en 1896, y en 1931 recibiâ”œâ”‚ la visita de la piqueta. Su patrimonio tangible tuvo vida movida, siendo una parte reutilizado, por ejemplo, en la nueva parroquia de San Valero (Delicias). Esta cercana imagen lateral de la iglesia ha sido capturada desde la propia calle de San Andrâ”œÂ®s, casi en la puerta de la Casa de Ganaderos (izquierda), que habâ”œÂ¡a estrenado nueva sede en 1914 diseâ”œâ–’ada por Teodoro Râ”œÂ¡os. Entre iglesia y Casa, un portillo entreabierto anuncia el "Callejâ”œâ”‚n de salida a la calle de San Andrâ”œÂ®s" desde el trasero solar donde se levantâ”œâ”‚ la antigua Casa de la Infanta. Al otro lado de la estrecha calle, viviendas de la manzana de Don Jaime I. Al fondo, pequeâ”œâ–’o alero volado de las viviendas de la calle de la Verâ”œâ”‚nica. Una rama de palma, abandonada en un balcâ”œâ”‚n, dice que la Semana Santa Catâ”œâ”‚lica ya ha tenido lugar. Fuente: Instituto Amatller de Arte Hispâ”œÃ­nico (Arxiu Mas).', 1918, 1918, 1918, 'Anos 10', 'CENTRO', 41.65255300, -0.87848700, '0101000020E6100000C2C1DEC4901CECBF0EF450DB86D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15894783705.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15894783705.webp', 'https://www.flickr.com/photos/zaragozaantigua/15894783705/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24387, 'San Juan y San Pedro c.1903', 'Cromolitografâ”œÂ¡a de Agustâ”œÂ¡n Alluâ”œÂ® para postal de la antigua torre parroquial mudâ”œÂ®jar de San Juan y San Pedro, basada en una imagen capturada desde la esquina de la calle Refugio con la calle de San Juan. Esta iglesia habâ”œÂ¡a sido levantada en el siglo XIV, de factura modesta, en ladrillo y tapial, pero con una sobresaliente decoraciâ”œâ”‚n mudâ”œÂ®jar en su atalaya. En el XVII recibiâ”œâ”‚ su actualizaciâ”œâ”‚n formal barroca, como era la moda de la â”œÂ®poca, y otros cambios estructuales. Originalmente de San Juan Bautista, o San Juan "el Viejo", para diferenciarla de la de San Juan del Puente, aâ”œâ–’adiâ”œâ”‚ la denominaciâ”œâ”‚n de San Pedro cuando esa vecina parroquia fue desacralizada en el XVIII. Estaba considerada la quinta gran torre mudâ”œÂ®jar de la ciudad, tras la Magdalena, San Miguel, San Pablo, y San Gil. Fue demolida integralmente en la prodigiosa dâ”œÂ®cada de los 60, sustituida por otro bloque de viviendas mâ”œÃ­s. Fuente visual: www.delcampe.net/', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.65334000, -0.87761700, '0101000020E6100000793C2D3F7015ECBF969526A5A0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23674291889.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23674291889.webp', 'https://www.flickr.com/photos/zaragozaantigua/23674291889/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24399, 'San Juan y San Pedro 1966', 'Vista, desde el interior demolido, de la torre de la iglesia de San Juan y San Pedro, en la confluencia de la calle homâ”œâ”‚nima con la del Refugio. El proceso de derribo de este edificio se iniciâ”œâ”‚ a finales de mayo de 1966 y concluyâ”œâ”‚ con la eliminaciâ”œâ”‚n de su torre pocos meses despuâ”œÂ®s. A espaldas del fotâ”œâ”‚grafo, la calle de San Juan y San Pedro, por la que se accedâ”œÂ¡a a la iglesia. Al fondo, a la derecha, traseras del patio del bloque de viviendas de San Jorge nâ”¬â•‘ 3.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65335300, -0.87755500, '0101000020E6100000F71E2E39EE14ECBF2BDF3312A1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28123196534.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28123196534.webp', 'https://www.flickr.com/photos/zaragozaantigua/28123196534/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24402, 'Iglesia de San Gil 1969', 'Vista en altura de la iglesia de San Gil desde la calle de Don Jaime I, con la calle de los Estâ”œÂ®banes a la derecha. Fuente: www.flickr.com/photos/114031783@N02/', 1969, 1969, 1969, 'Anos 60', 'CENTRO', 41.65279000, -0.87940100, '0101000020E6100000F33AE2900D24ECBFF3936A9F8ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29398562991.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29398562991.webp', 'https://www.flickr.com/photos/zaragozaantigua/29398562991/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24405, 'Calle Estâ”œÂ®banes 2003', 'Foto: Javier Torres. Fachada de la iglesia de San Gil recayente a la calle de los Estâ”œÂ®banes, con el muro producto de los derribos en 2002 de las edificaciones anexas, que luego serâ”œÃ­ rehabilitado. Fuente: www.facebook.com/photo.php?fbid=161205391009071&set=p...', 2003, 2003, 2003, 'Siglo XXI', 'CENTRO', 41.65283800, -0.87938000, '0101000020E610000016359886E123ECBF04CB113290D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30010083203.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30010083203.webp', 'https://www.flickr.com/photos/zaragozaantigua/30010083203/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24523, 'Calle de San Jorge 1929', 'Dibujo publicitario del local comercial que la Casa Guiral (desde 1940, Guiral Industrias Elâ”œÂ®ctricas S. A. o GIESA) abriâ”œâ”‚ en los bajos del gran edificio diseâ”œâ–’ado por el joven arquitecto Alberto Huerta Marâ”œÂ¡n en la parcela ubicada entre las calles de San Andrâ”œÂ®s y de San Jorge, y construido a principios de la dâ”œÂ®cada. Esta tienda destacaba por su gran exposiciâ”œâ”‚n de cristalerâ”œÂ¡a y por un interesante muestrario de "aparatos de fantasâ”œÂ¡a" vinculados al moderno mundo de la electricidad aplicada al sector domâ”œÂ®stico. La referida "fantasâ”œÂ¡a" parece ser que despistâ”œâ”‚ a los impresores, pues la publicaron boca abajo, con las lâ”œÃ­mparas ancladas en el suelo y los pesados motores pegados al techo. En GAZA, gratis et amore, le hemos dado la vuelta a la imagen para restaurar el sentido original que seguramente tenâ”œÂ¡a Joaquâ”œÂ¡n Guiral cuando contratâ”œâ”‚ esta publicidad. Al fondo, en el centro, ventanal en arco carpanel recayente a la calle de San Andrâ”œÂ®s. A la izquierda, la chaflanera puerta de ingreso correspondiente al nâ”œâ•‘mero 6-8 de la calle de San Jorge. Fuente visual: www.mecd.gob.es/.', 1929, 1929, 1929, 'Anos 20', 'CENTRO', 41.65299600, -0.87817500, '0101000020E61000000B462575021AECBF9C35785F95D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39510007472.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39510007472.webp', 'https://www.flickr.com/photos/zaragozaantigua/39510007472/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24527, 'Calle de San Jorge 1991', 'Imagen centrada en el referencial chaflâ”œÃ­n del nâ”¬â•‘ 17-19 de la calle de San Andrâ”œÂ®s (posiblemente donde antes estuviera la casa del conde de Montemar) realizado en 1922 segâ”œâ•‘n proyecto del arquitecto zaragozano Alberto Huerta Marâ”œÂ¡n para Joaquâ”œÂ¡n Guiral (desde 1940 GIESA, Guiral Industrias Elâ”œÂ®ctricas SA), de forma que la planta calle fue habilitada como gran local comercial de productos elâ”œÂ®ctricos que incluâ”œÂ¡an algunos de los fabricados, primero en la calle de Roda, luego en la planta del camino de San Josâ”œÂ® y finalmente en la de la calle de Miguel Servet. Las dos plantas superiores fueron diseâ”œâ–’adas para uso residencial. Pocos aâ”œâ–’os despuâ”œÂ®s, el edificio fue rehabilitado de forma integral, desapareciendo el original uso industrial.', 1991, 1991, 1991, 'Anos 90', 'CENTRO', 41.65299600, -0.87817500, '0101000020E61000000B462575021AECBF9C35785F95D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/43075811201.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/43075811201.webp', 'https://www.flickr.com/photos/zaragozaantigua/43075811201/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24531, 'Calle de San Jorge c.1949', 'Imagen capturada desde cierta altura en el inmueble del nâ”¬â•‘ 3 de la calle de San Jorge, y centrado en el esquinero local comercial con la calle de San Andrâ”œÂ®s (a la izquierda) construido a principios de la dâ”œÂ®cada de los aâ”œâ–’os 20 segâ”œâ•‘n proyecto del arquitecto zaragozano Alberto Huerta Marâ”œÂ¡n, para dar salida a los productos elâ”œÂ®ctricos de Joaquâ”œÂ¡n Guiral (desde 1940 GIESA, Guiral Industrias Elâ”œÂ®ctricas SA), construidos primero en calle de Roda, luego en la temporal planta del camino de San Josâ”œÂ®, y finalmente en la nueva gran factorâ”œÂ¡a de la calle de Miguel Servet. Las dos plantas superiores fueron diseâ”œâ–’adas para uso residencial. Una reforma posterior aâ”œâ–’adiâ”œâ”‚ una planta extra y eliminâ”œâ”‚ la singular balaustrada que hasta entonces culminaba el edificio, A la derecha y al fondo, la calle de Don Jaime I.', 1949, 1949, 1949, 'Anos 40', 'CENTRO', 41.65291300, -0.87817600, '0101000020E6100000213A048E041AECBF0E1137A792D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48414704521.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48414704521.webp', 'https://www.flickr.com/photos/zaragozaantigua/48414704521/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24866, 'Calle de Don Jaime I 1976', 'Imagen capturada desde la altura del inmueble del nâ”¬â•‘ 18 de la calle de Don Jaime I, con vista en perspectiva del denso trâ”œÃ­fico rodado que transitaba por esta câ”œÂ®ntrica vâ”œÂ¡a de la ciudad antigua, hasta con tres carriles de circulaciâ”œâ”‚n, y el detalle del carril bus ideado para tratar de dar fluidez al servicio de las lâ”œÂ¡neas de bus, como la nâ”¬â•‘ 32 "Gâ”œÃ­llego-Delicias", que habâ”œÂ¡an sustituido a algunas de las histâ”œâ”‚ricas lâ”œÂ¡neas de tranvâ”œÂ¡a en el transporte pâ”œâ•‘blico. Este carril-bus serâ”œÂ¡a eliminado despuâ”œÂ®s. La transiciâ”œâ”‚n hacia la pacificaciâ”œâ”‚n del trâ”œÃ­fico en esta vâ”œÂ¡a todavâ”œÂ¡a sigue su curso.', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.65301800, -0.87863800, '0101000020E61000002CBB6070CD1DECBF84D9041896D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48088268623.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48088268623.webp', 'https://www.flickr.com/photos/zaragozaantigua/48088268623/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24917, 'Teatro romano 2003', 'Vista de las obras de rehabilitaciâ”œâ”‚n del Teatro romano en enero de 2003, con la calle de la Verâ”œâ”‚nica al fondo. Fuente: Agencia EFE.', 2003, 2003, 2003, 'Siglo XXI', 'CENTRO', 41.65215200, -0.87767200, '0101000020E61000005CAD1397E315ECBFB0027CB779D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24375973250.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24375973250.webp', 'https://www.flickr.com/photos/zaragozaantigua/24375973250/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
