INSERT INTO public.photos VALUES (25088, 'J.A. Labordeta 1964', '"10 de marzo [1935] -cumpleaâ”œâ–’os feliz-. Nunca vuelven los infinitos dâ”œÂ¡as de la infancia..." (Josâ”œÂ® Antonio Labordeta, Diario de un nâ”œÃ­ufrago). Fuente visual: foto Gerardo Sancho Ramo, capturada en el Teatro Principal, AMZ.', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.65199400, -0.87944100, '0101000020E6100000815EB8736124ECBF1898158A74D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32066721273.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32066721273.webp', 'https://www.flickr.com/photos/zaragozaantigua/32066721273/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25151, 'Calle Ossau aâ”œâ–’os 30', 'Acuarela de Ambrosio Ruste, mostrando la calle de Ossau, antes de ser ensanchada en los aâ”œâ–’os cincuenta. Al fondo, la calle de Casto Mâ”œÂ®ndez Nâ”œâ•‘â”œâ–’ez. Fuente: Lâ”œÃ­minas de A. Ruste. AMZ 1977.', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.65323900, -0.87942300, '0101000020E6100000E7340BB43B24ECBF62BCE6559DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31597069924.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31597069924.webp', 'https://www.flickr.com/photos/zaragozaantigua/31597069924/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25187, 'Calle de los Estâ”œÂ®banes 1980', 'Dibujo realizado en el desemboque de la calle de Josâ”œÂ® Pellicer Ossau (antigua de las Moscas) en la de los Estâ”œÂ®banes y centrado en el lado de la epâ”œÂ¡stola de la iglesia parroquial de San Gil Abad, de donde emerge su torre. Al fondo, la calle de Don Jaime I y a la derecha, el final de la calle de Cinegio.', 1980, 1980, 1980, 'Anos 80', 'CENTRO', 41.65299400, -0.87962500, '0101000020E6100000D9CEF753E325ECBFFB3DB14E95D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53264457311.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53264457311.webp', 'https://www.flickr.com/photos/zaragozaantigua/53264457311/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25644, 'Calle Verâ”œâ”‚nica 1966', 'AYUNTAMIENTO DE ZARAGOZA/Gerardo Sancho Ramo. 24/12/1966. Captura desde la calle Verâ”œâ”‚nica del estado de las cosas en lo que hoy es la plaza Josâ”œÂ® Sinuâ”œÂ®s, entonces una manzana de viviendas. Al fondo, la calle Don Jaime I. A la izquierda, el edificio del Teatro Principal. Una unidad 200 de la Lâ”œÂ¡nea 13 "San Josâ”œÂ®" del tranvâ”œÂ¡a, que apenas un aâ”œâ–’o despuâ”œÂ®s se unificarâ”œÂ¡a con la lâ”œÂ¡nea 11, "Parque", conformando la nueva Lâ”œÂ¡nea 11 "Parque-San Josâ”œÂ®" (la â”œâ•‘ltima en ser piqueteada, en enero de 1976). En el centro de la imagen, la manzana de viviendas delimitada por Don Jaime, Verâ”œâ”‚nica (derecha), y la calle Valentâ”œÂ¡n Zabala (izquierda), estâ”œÃ­ empezando a ser preparada para el derribo. A la derecha, el chaflâ”œÃ­n del edificio que aâ”œâ•‘n perdura en nuestro dâ”œÂ¡as anuncia el emboque con la calle San Andrâ”œÂ®s. De resultas de esta intervenciâ”œâ”‚n, la calle Verâ”œâ”‚nica se vio acortada un tramo, la calle Valentâ”œÂ¡n Zabala desapareciâ”œâ”‚, y hoy tenemos la Plaza Josâ”œÂ® Sinuâ”œÂ®s.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65207200, -0.87880400, '0101000020E6100000EB01F390291FECBF9351651877D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14666062227.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14666062227.webp', 'https://www.flickr.com/photos/zaragozaantigua/14666062227/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25645, 'Casa de Zaporta c.1877', 'Archivo RUIZ VERNACCI, Jean Laurent y Câ”œÂ¡a. 1872-1879. Patio de la Casa de Zaporta, o de la Infanta.', 1877, 1877, 1877, 'Siglo XIX', 'CENTRO', 41.65260900, -0.87750600, '0101000020E61000009D6681768714ECBFA20914B188D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14679462819.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14679462819.webp', 'https://www.flickr.com/photos/zaragozaantigua/14679462819/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
