INSERT INTO public.photos VALUES (25655, 'Vista parroquia San Gil aâ”œâ–’os 20', 'Miguel Faci Abad. 1920-25. "Zaragoza. Vista de la parroquia de San Gil." Desde las alturas del Casino Mercantil, ya de tarde, una vista panorâ”œÃ­mica hacia el este, que comprende: San Juan y San Pedro, San Gil, la Magdalena, la sede de una entidad local de ahorro (sin su caracterâ”œÂ¡stico remate en linterna), San Pedro Nolasco, San Andrâ”œÂ®s, San Carlos Borromeo... Fuente visual: "Miguel y Gabriel Faci. Fotâ”œâ”‚grafos fundadores de la Real Sociedad Fotogrâ”œÃ­fica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaciâ”œâ”‚n Provincial de Zaragoza, 1999.', 1920, 1920, 1929, 'Anos 20', 'CENTRO', 41.65276600, -0.87918900, '0101000020E61000001E1840F85022ECBF6AF816D68DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15339596309.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15339596309.webp', 'https://www.flickr.com/photos/zaragozaantigua/15339596309/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25656, 'Don Jaime I 1966', 'Archivo Municipal. Gerardo Sancho Ramo. Mayo de 1966 Por la calle Don Jaime I, espectacular riada-marabunta de circulaciâ”œâ”‚n rodada proveniente del Puente de las Piedras. En teorâ”œÂ¡a habâ”œÂ¡a tres carriles, pero muy plâ”œÃ­sticos, y podâ”œÂ¡an llegar a cuatro en algunos tramos. Vale que los coches eran mâ”œÃ­s "latensardinen", no como los "panzer" de hoy en dâ”œÂ¡a, pero la tendencia era esta. La imagen estâ”œÃ­ tomada en altura, desde un balcâ”œâ”‚n de los nâ”œâ•‘meros pares, con visual inmediata de las calles San Jorge, a la derecha, Mâ”œÂ®ndez Nâ”œâ•‘â”œâ–’ez, a la izquierda, y la plaza de Ariâ”œâ–’o un poco mâ”œÃ­s adelante, y a la izquierda tambiâ”œÂ®n.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65311100, -0.87849600, '0101000020E61000008F56B5A4A31CECBF35D4282499D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15562995082.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15562995082.webp', 'https://www.flickr.com/photos/zaragozaantigua/15562995082/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25658, 'Verâ”œâ”‚nica-Zabala 1967', 'Archivo Municipal. Gerardo Sancho Ramo. 1967. Imagen del solar dejado por la manzana derribada entre las calles de la Verâ”œâ”‚nica y de Zabala, desde la calle de Don Jaime I. Al fondo, el Teatro Principal. En medio, publicidad de una entidad local de ahorro. Este serâ”œÃ­ el emplazamiento de la plaza de Sinuâ”œÂ®s.', 1967, 1967, 1967, 'Anos 60', 'CENTRO', 41.65230400, -0.87912600, '0101000020E6100000850662D9CC21ECBF66868DB27ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15717640462.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15717640462.webp', 'https://www.flickr.com/photos/zaragozaantigua/15717640462/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25659, 'Calle de los Estâ”œÂ®banes 1962', 'Foto: Joan Miquel i Quintilla. Confluencia de la calle de Don Jaime I (desde donde estâ”œÃ­ realizada la imagen) y la calle de los Estâ”œÂ®banes. La pared de la izquierda corresponde a la iglesia de San Gil Abad, y la construcciâ”œâ”‚n donde se ve el quiosco de prensa fue edificio anexo al templo, hoy retirado. Fuente visual: barcelonafotoantic.com/', 1962, 1962, 1962, 'Anos 60', 'CENTRO', 41.65276600, -0.87918900, '0101000020E61000001E1840F85022ECBF6AF816D68DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16785044566.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16785044566.webp', 'https://www.flickr.com/photos/zaragozaantigua/16785044566/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25660, 'San Jorge c.1925', 'Imagen levemente aâ”œÂ®rea de la confluencia de la calle San Jorge (izquierda) y San Andrâ”œÂ®s, en un entorno dominado (no solo visualmente) por el reciente edificio de la sede central de una indâ”œÂ¡gena entidad de ahorro, levantado justo encima de la piqueteada primero, y llorada despuâ”œÂ®s (a lo aligator) Casa de Zaporta. A la izquierda, aunque invisible, sigue en pie la pequeâ”œâ–’a iglesia de San Andrâ”œÂ®s; detrâ”œÃ­s, lo mismo sucede con la original iglesia de San Pedro Nolasco. Unos pocos aâ”œâ–’os despuâ”œÂ®s, ambas serâ”œÃ­n procesadas. Al fondo, la torre de la Magdalena con su particular atavâ”œÂ¡o barroco-neoclâ”œÃ­sico. Fuente visual: Fundaciâ”œâ”‚n Telefâ”œâ”‚nica', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65285400, -0.87797400, '0101000020E610000030A017EE5C18ECBF098849B890D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16824948379.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16824948379.webp', 'https://www.flickr.com/photos/zaragozaantigua/16824948379/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25661, 'Casa de Zaporta 1860', '"Zaragoza, Patio de la Casa de los Infantes" (sic). Gabriel Zaporta pagâ”œâ”‚ su construcciâ”œâ”‚n en 1550 como casa familiar, en incomparables formas y estilo renacentista. En 1636 pasâ”œâ”‚ a ser propiedad de la familia Albiâ”œâ”‚n, y luego de los Franco. En los siglos XVII y XVIII siguiâ”œâ”‚ cambiando de manos. En el XIX, su enorme espacio fue tabicado para albergar arrendamientos y usos dispares: Liceo Artâ”œÂ¡stico y Literario, taller de carruajes, taller de carpinterâ”œÂ¡a y ebanisterâ”œÂ¡a, fâ”œÃ­brica de pianos... En 1871, era tal su degradaciâ”œâ”‚n, que su patio fue restaurado, antes de ser arrendado para sede del Casino Monâ”œÃ­rquico Liberal. En la imagen, aspecto parcial del patio central del palacio antes de esa restauraciâ”œâ”‚n, cuando estaba tabicado para delimitar estancias y salas mâ”œÃ­s pequeâ”œâ–’as. Fuente visual: Charles Clifford, en www.balclis.com/', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.65266300, -0.87754700, '0101000020E6100000417E3672DD14ECBF952710768AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17241874332.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17241874332.webp', 'https://www.flickr.com/photos/zaragozaantigua/17241874332/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25665, 'Calle de Don Jaime I 1924', 'Imagen desde cierta altura del reciente nâ”¬â•‘ 14 (numeraciâ”œâ”‚n actual) de la calle Don Jaime I, chaflanero con el principio de la calle de la Verâ”œâ”‚nica, que por la derecha se va culebreando hacia la plazuela del mismo nombre. Si en la imagen esta calle parece estrecha, habrâ”œÂ¡a que haberla visto antes del ensanchamiento realizado al hilo de la construcciâ”œâ”‚n de este nuevo edificio, proyectado por Teodoro Râ”œÂ¡os Balaguer en formas muy poco usuales para la ciudad. Quedaba sin realizar la parte recayente a la calle de San Andrâ”œÂ®s, cerrada con muro, que serâ”œÃ­ completada a finales de los aâ”œâ–’os 40, en un estilo completamente diferente, con mucho predicamento local, regionalista, regimentalista. Enfrente, el nâ”¬â•‘ 2 de San Andrâ”œÂ®s, vecino de la iglesia del protocletos, que quedaba a su izquierda. A la izquierda, e inmediato, se deja entrever el solar del futuro nâ”¬â•‘ 16 de Don Jaime I. Fuente visual: Archivo Juan Mora Insa (DARA-AHPZ).', 1924, 1924, 1924, 'Anos 20', 'CENTRO', 41.65257100, -0.87907600, '0101000020E6100000145AD6FD6321ECBFB5A84F7287D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22513632202.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22513632202.webp', 'https://www.flickr.com/photos/zaragozaantigua/22513632202/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
